## JavaScript Debounce 函数

一个标准的、可配置的 debounce 实现，支持 **trailing**（默认）、**leading** 和 **取消/刷新**：

```javascript
/**
 * 创建一个防抖函数 —— 在连续高频触发时，
 * 只在「最后一次调用后等待 wait 毫秒」才真正执行。
 *
 * @param {Function} fn      要防抖的目标函数
 * @param {number}   wait    等待毫秒数
 * @param {Object}   options
 * @param {boolean}  options.leading  是否在延时开始时立即执行一次（默认 false）
 * @param {boolean}  options.trailing 是否在延时结束后执行（默认 true）
 * @param {number}   options.maxWait  最大等待时间（可选，类似 lodash maxWait）
 * @returns {Function} 防抖后的函数，附带 .cancel() 和 .flush()
 */
function debounce(fn, wait, options = {}) {
  const { leading = false, trailing = true, maxWait } = options;

  let timer = null;           // setTimeout 句柄
  let lastCallTime = 0;       // 上次被调用的时间戳
  let lastInvokeTime = 0;     // 上次实际执行的时间戳
  let lastArgs = null;        // 最近一次传入的参数
  let lastThis = null;        // 最近一次的 this 上下文
  let result = undefined;     // 最后一次 fn 的返回值（仅 trailing 可返回）

  // 是否已过等待期
  const shouldInvoke = (time) => {
    const timeSinceLastCall = time - lastCallTime;
    return (
      lastCallTime === 0 ||           // 从未调用过
      timeSinceLastCall >= wait ||    // 间隔已超过 wait
      timeSinceLastCall < 0           // 系统时间被回拨
    );
  };

  // 实际执行 fn
  const invokeFn = (time) => {
    const args = lastArgs;
    const thisArg = lastThis;

    lastArgs = lastThis = null;
    lastInvokeTime = time;
    result = fn.apply(thisArg, args);
    return result;
  };

  // 开启延时（trailing）
  const startTimer = (pendingExpiry) => {
    if (timer) clearTimeout(timer);
    timer = setTimeout(timerExpired, pendingExpiry);
  };

  // trailing 计时结束 → 执行
  const timerExpired = () => {
    const time = Date.now();
    if (shouldInvoke(time)) {
      if (trailing) invokeFn(time);
      timer = null;
    } else {
      // 还在冷却中，重新计时
      startTimer(wait - (time - lastCallTime));
    }
  };

  // leading 逻辑
  const leadingEdge = (time) => {
    lastInvokeTime = time;
    if (leading) invokeFn(time);
    startTimer(wait); // 同时安排 trailing
  };

  // 核心防抖函数
  const debounced = function (...args) {
    const time = Date.now();
    const isInvoking = shouldInvoke(time);

    lastArgs = args;
    lastThis = this; // eslint-disable-line consistent-this
    lastCallTime = time;

    if (isInvoking) {
      if (timer === null) {
        leadingEdge(time);
      } else if (maxWait) {
        // 如果设置了 maxWait，检查是否需要强制刷新
        const timeSinceLastInvoke = time - lastInvokeTime;
        if (timeSinceLastInvoke >= maxWait) {
          timerExpired();
        }
      }
    }
    if (timer === null && trailing) {
      // trailing 模式下重新安排
      startTimer(wait);
    }

    return result;
  };

  // 取消待执行的任务
  debounced.cancel = () => {
    if (timer !== null) {
      clearTimeout(timer);
      timer = null;
    }
    lastArgs = lastThis = lastCallTime = lastInvokeTime = 0;
  };

  // 立即执行 pending 中的调用
  debounced.flush = () => {
    if (timer !== null) {
      timerExpired();
    }
    return result;
  };

  // 是否在等待中
  debounced.pending = () => timer !== null;

  return debounced;
}
```

---

### 使用示例

```javascript
// 1️⃣ 基本用法：输入框搜索，用户停止打字 300ms 后请求
const search = debounce(
  (query) => fetch(`/api/search?q=${query}`),
  300
);
searchInput.addEventListener('input', (e) => search(e.target.value));

// 2️⃣ leading: 第一次立即执行，之后防抖
const click = debounce(
  () => console.log('点击防抖'),
  1000,
  { leading: true, trailing: false }
);
// 多次点击 → 只有第一次立即执行

// 3️⃣ cancel / flush
const log = debounce(() => console.log('hello'), 500);
log();
log();
log.cancel(); // 取消，不输出

const log2 = debounce(() => console.log('world'), 500);
log2();
log2.flush(); // 立即输出 "world"
```

---

### 核心原理

| 概念 | 说明 |
|------|------|
| **Trailing**（默认） | 高频触发后，停下来的那一刻才执行 |
| **Leading** | 第一次触发立即执行，后续高频触发被忽略 |
| **cancel()** | 清除未执行的定时器 |
| **flush()** | 立即执行 pending 的调用 |

用一句话记：**debounce 把一连串的「哒哒哒哒哒」压成一个「哒——」（最后一次）或「哒——哒——」（第一次 + 最后一次）。**

